3107	    let thread_name = format!("clawd-agent-{}", job.manifest.agent_id);
3108	    std::thread::Builder::new()
3109	        .name(thread_name)
3110	        .spawn(move || {
3111	            let result =
3112	                std::panic::catch_unwind(std::panic::AssertUnwindSafe(|| run_agent_job(&job)));
3113	            match result {
3114	                Ok(Ok(())) => {}
3115	                Ok(Err(error)) => {
3116	                    let _ =
3117	                        persist_agent_terminal_state(&job.manifest, "failed", None, Some(error));
3118	                }
3119	                Err(_) => {
3120	                    let _ = persist_agent_terminal_state(
3121	                        &job.manifest,
