1	//! Lane completion detector — automatically marks lanes as completed when
2	//! session finishes successfully with green tests and pushed code.
3	//!
4	//! This bridges the gap where `LaneContext::completed` was a passive bool
5	//! that nothing automatically set. Now completion is detected from:
6	//! - Agent output shows Finished status
7	//! - No errors/blockers present  
8	//! - Tests passed (green status)
9	//! - Code pushed (has output file)
10	
11	use runtime::{
12	    evaluate, LaneBlocker, LaneContext, PolicyAction, PolicyCondition, PolicyEngine, PolicyRule,
13	    ReviewStatus,
14	};
15	
16	use crate::AgentOutput;
17	
18	/// Detects if a lane should be automatically marked as completed.
19	/// 
20	/// Returns `Some(LaneContext)` with `completed = true` if all conditions met,
21	/// `None` if lane should remain active.
22	pub(crate) fn detect_lane_completion(
23	    output: &AgentOutput,
24	    test_green: bool,
25	    has_pushed: bool,
26	) -> Option<LaneContext> {
27	    // Must be finished without errors
28	    if output.error.is_some() {
29	        return None;
30	    }
31	    
32	    // Must have finished status
33	    if !output.status.eq_ignore_ascii_case("completed")
34	        && !output.status.eq_ignore_ascii_case("finished")
35	    {
36	        return None;
37	    }
38	    
39	    // Must have no current blocker
40	    if output.current_blocker.is_some() {
41	        return None;
42	    }
43	    
44	    // Must have green tests
45	    if !test_green {
46	        return None;
47	    }
48	    
49	    // Must have pushed code
50	    if !has_pushed {
51	        return None;
52	    }
53	    
54	    // All conditions met — create completed context
55	    Some(LaneContext {
56	        lane_id: output.agent_id.clone(),
57	        green_level: 3, // Workspace green
58	        branch_freshness: std::time::Duration::from_secs(0),
59	        blocker: LaneBlocker::None,
60	        review_status: ReviewStatus::Approved,
61	        diff_scope: runtime::DiffScope::Scoped,
62	        completed: true,
63	        reconciled: false,
64	    })
65	}
66	
67	/// Evaluates policy actions for a completed lane.
68	pub(crate) fn evaluate_completed_lane(
69	    context: &LaneContext,
70	) -> Vec<PolicyAction> {
71	    let engine = PolicyEngine::new(vec![
72	        PolicyRule::new(
73	            "closeout-completed-lane",
74	            PolicyCondition::And(vec![
75	                PolicyCondition::LaneCompleted,
76	                PolicyCondition::GreenAt { level: 3 },
77	            ]),
78	            PolicyAction::CloseoutLane,
79	            10,
80	        ),
81	        PolicyRule::new(
82	            "cleanup-completed-session",
83	            PolicyCondition::LaneCompleted,
84	            PolicyAction::CleanupSession,
85	            5,
86	        ),
87	    ]);
88	    
89	    evaluate(&engine, context)
90	}
