3431	            model: self.model.clone(),
3432	            max_tokens: max_tokens_for_model(&self.model),
3433	            messages: convert_messages(&request.messages),
3434	            system: (!request.system_prompt.is_empty()).then(|| request.system_prompt.join("\n\n")),
3435	            tools: (!tools.is_empty()).then_some(tools),
3436	            tool_choice: (!self.allowed_tools.is_empty()).then_some(ToolChoice::Auto),
3437	            stream: true,
3438	        };
3439	
3440	        self.runtime.block_on(async {
3441	            let mut stream = self
3442	                .client
3443	                .stream_message(&message_request)
3444	                .await
3445	                .map_err(|error| RuntimeError::new(error.to_string()))?;
3446	            let mut events = Vec::new();
3447	            let mut pending_tools: BTreeMap<u32, (String, String, String)> = BTreeMap::new();
3448	            let mut saw_stop = false;
3449	
3450	            while let Some(event) = stream
3451	                .next_event()
3452	                .await
3453	                .map_err(|error| RuntimeError::new(error.to_string()))?
3454	            {
3455	                match event {
3456	                    ApiStreamEvent::MessageStart(start) => {
3457	                        for block in start.message.content {
3458	                            push_output_block(block, 0, &mut events, &mut pending_tools, true);
3459	                        }
3460	                    }
3461	                    ApiStreamEvent::ContentBlockStart(start) => {
3462	                        push_output_block(
3463	                            start.content_block,
3464	                            start.index,
3465	                            &mut events,
3466	                            &mut pending_tools,
3467	                            true,
3468	                        );
3469	                    }
3470	                    ApiStreamEvent::ContentBlockDelta(delta) => match delta.delta {
3471	                        ContentBlockDelta::TextDelta { text } => {
3472	                            if !text.is_empty() {
3473	                                events.push(AssistantEvent::TextDelta(text));
3474	                            }
3475	                        }
3476	                        ContentBlockDelta::InputJsonDelta { partial_json } => {
3477	                            if let Some((_, _, input)) = pending_tools.get_mut(&delta.index) {
3478	                                input.push_str(&partial_json);
3479	                            }
3480	                        }
3481	                        ContentBlockDelta::ThinkingDelta { .. }
3482	                        | ContentBlockDelta::SignatureDelta { .. } => {}
3483	                    },
3484	                    ApiStreamEvent::ContentBlockStop(stop) => {
3485	                        if let Some((id, name, input)) = pending_tools.remove(&stop.index) {
3486	                            events.push(AssistantEvent::ToolUse { id, name, input });
3487	                        }
3488	                    }
3489	                    ApiStreamEvent::MessageDelta(delta) => {
3490	                        events.push(AssistantEvent::Usage(delta.usage.token_usage()));
3491	                    }
3492	                    ApiStreamEvent::MessageStop(_) => {
3493	                        saw_stop = true;
3494	                        events.push(AssistantEvent::MessageStop);
3495	                    }
3496	                }
3497	            }
3498	
3499	            push_prompt_cache_record(&self.client, &mut events);
3500	
3501	            if !saw_stop
3502	                && events.iter().any(|event| {
3503	                    matches!(event, AssistantEvent::TextDelta(text) if !text.is_empty())
3504	                        || matches!(event, AssistantEvent::ToolUse { .. })
3505	                })
3506	            {
3507	                events.push(AssistantEvent::MessageStop);
3508	            }
3509	
3510	            if events
3511	                .iter()
3512	                .any(|event| matches!(event, AssistantEvent::MessageStop))
3513	            {
3514	                return Ok(events);
3515	            }
3516	
3517	            let response = self
3518	                .client
3519	                .send_message(&MessageRequest {
3520	                    stream: false,
3521	                    ..message_request.clone()
3522	                })
3523	                .await
3524	                .map_err(|error| RuntimeError::new(error.to_string()))?;
3525	            let mut events = response_to_events(response);
3526	            push_prompt_cache_record(&self.client, &mut events);
3527	            Ok(events)
3528	        })
3529	    }
3530	}
