1263	fn run_ask_user_question(input: AskUserQuestionInput) -> Result<String, String> {
1264	    use std::io::{self, BufRead, Write};
1265	
1266	    // Display the question to the user via stdout
1267	    let stdout = io::stdout();
1268	    let stdin = io::stdin();
1269	    let mut out = stdout.lock();
1270	
1271	    writeln!(out, "\n[Question] {}", input.question).map_err(|e| e.to_string())?;
1272	
1273	    if let Some(ref options) = input.options {
1274	        for (i, option) in options.iter().enumerate() {
1275	            writeln!(out, "  {}. {}", i + 1, option).map_err(|e| e.to_string())?;
1276	        }
1277	        write!(out, "Enter choice (1-{}): ", options.len()).map_err(|e| e.to_string())?;
1278	    } else {
1279	        write!(out, "Your answer: ").map_err(|e| e.to_string())?;
1280	    }
1281	    out.flush().map_err(|e| e.to_string())?;
1282	
1283	    // Read user response from stdin
1284	    let mut response = String::new();
1285	    stdin
1286	        .lock()
1287	        .read_line(&mut response)
1288	        .map_err(|e| e.to_string())?;
1289	    let response = response.trim().to_string();
1290	
1291	    // If options were provided, resolve the numeric choice
1292	    let answer = if let Some(ref options) = input.options {
1293	        if let Ok(idx) = response.parse::<usize>() {
1294	            if idx >= 1 && idx <= options.len() {
1295	                options[idx - 1].clone()
1296	            } else {
1297	                response.clone()
1298	            }
1299	        } else {
1300	            response.clone()
1301	        }
1302	    } else {
1303	        response.clone()
1304	    };
1305	
1306	    to_pretty_json(json!({
1307	        "question": input.question,
1308	        "answer": answer,
1309	        "status": "answered"
1310	    }))
1311	}
